{
  "title": "Beginner Piano Mastery",
  "description": "A comprehensive course designed for beginners to build a strong foundation in piano playing, music theory, and performance skills.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Piano Basics",
      "description": "Learn the layout of the piano, basic music notation, and fundamental techniques for proper hand positioning and posture."
    },
    {
      "id": "module2",
      "title": "Essential Music Theory",
      "description": "Understand the basics of music theory, including scales, chords, and rhythm, to enhance your playing and comprehension of music."
    },
    {
      "id": "module3",
      "title": "Playing Simple Melodies",
      "description": "Practice playing simple melodies and songs, focusing on timing, dynamics, and expression to develop your musicality."
    },
    {
      "id": "module4",
      "title": "Introduction to Improvisation and Composition",
      "description": "Explore the basics of improvisation and composition, encouraging creativity and personal expression in your piano playing."
    }
  ]
}
